import NetworkErrorOverlay from '@/components/NetworkErrorOverlay';
import PropertyForm from '@/components/PropertyForm';
import BinnacleView from '@/components/BinnacleView';
import WhatsAppNotificationModal from '@/components/WhatsAppNotificationModal';

// Import Modals
import AddVisitModal from '@/components/AddVisitModal';
import EditVisitModal from '@/components/EditVisitModal';
import VisitDetailsModal from '@/components/VisitDetailsModal';
import ConfirmationModal from '@/components/ConfirmationModal';
import AddTaskModal from '@/components/AddTaskModal';
import EditTaskModal from '@/components/EditTaskModal';
import AddEventModal from '@/components/AddEventModal';
import EditEventModal from '@/components/EditEventModal';
import CalendarActionModal from '@/components/CalendarActionModal';
import CalendarItemDetailsModal from '@/components/CalendarItemDetailsModal';
import ScheduleVisitModal from '@/components/ScheduleVisitModal';
import FileUploadWarningModal from '@/components/FileUploadWarningModal';

// Import Types & Icons
import { User, UserRole, TaskStatus, Notification, Property, Task, DailyLog, CaptacionStatus } from '@/types';
import { ChartPieIcon } from '@/components/icons/ChartPieIcon';
import { BuildingOfficeIcon } from '@/components/icons/BuildingOfficeIcon';
import { UsersIcon } from '@/components/icons/UsersIcon';
import { AcademicCapIcon } from '@/components/icons/AcademicCapIcon';
import { ClipboardDocumentCheckIcon } from '@/components/icons/ClipboardDocumentCheckIcon';
import { CalendarDaysIcon } from '@/components/icons/CalendarDaysIcon';
import { CogIcon } from '@/components/icons/CogIcon';
import { DocumentTextIcon } from '@/components/icons/DocumentTextIcon';
import { ClipboardDocumentListIcon } from "@/components/icons/ClipboardDocumentListIcon";

const NavItem = ({ icon, label, isActive, onClick }: { icon: React.ReactNode, label: string, isActive: boolean, onClick: () => void }) => (
  <li>
    <button
      onClick={onClick}
      className={`flex items-center w-full p-3 rounded-lg text-left transition-colors ${isActive
          ? 'bg-orange-500 text-white shadow'
          : 'text-slate-600 hover:bg-orange-50 hover:text-orange-600'
        }`}
    >
      <span className="h-6 w-6">{icon}</span>
      <span className="ml-3 font-medium">{label}</span>
    </button>
  </li>
);

const Sidebar = ({ activeView, onNavigate, currentUser, isSidebarOpen }: { activeView: string, onNavigate: (view: string) => void, currentUser: User, isSidebarOpen: boolean }) => {
  const isCurrentUserAdmin = currentUser.role === UserRole.ADMIN;

  const navItems = [
    { view: 'dashboard', label: 'Dashboard', icon: <ChartPieIcon />, adminOnly: false },
    { view: 'properties', label: 'Propiedades', icon: <BuildingOfficeIcon />, adminOnly: false },
    { view: 'calendar', label: 'Calendario', icon: <CalendarDaysIcon />, adminOnly: false },
    { view: 'captaciones', label: 'Captaciones', icon: <ClipboardDocumentCheckIcon />, adminOnly: false },
    { view: 'binnacle', label: 'Bitácora', icon: <ClipboardDocumentListIcon />, adminOnly: false },
    { view: 'reports', label: 'Reportes', icon: <ChartPieIcon />, adminOnly: true },
    { view: 'manage-users', label: 'Usuarios', icon: <UsersIcon />, adminOnly: true },
    { view: 'training', label: 'Capacitaciones', icon: <AcademicCapIcon />, adminOnly: false },
    { view: 'formatos', label: 'Formatos', icon: <DocumentTextIcon />, adminOnly: false },
    { view: 'settings', label: 'Ajustes', icon: <CogIcon />, adminOnly: true },
  ];

  const availableNavItems = navItems.filter(item => !item.adminOnly || isCurrentUserAdmin);

  return (
    <aside className={`fixed top-0 left-0 h-full bg-white border-r border-slate-200 z-40 transition-transform transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 md:w-64 flex-shrink-0`}>
      <div className="p-4">
        <h2 className="text-2xl font-bold text-orange-500 mb-8">AquivivirApp</h2>
        <ul className="space-y-2">
          {availableNavItems.map(item => (
            <NavItem
              key={item.view}
              icon={item.icon}
              label={item.label}
              isActive={activeView === item.view}
              onClick={() => onNavigate(item.view)}
            />
          ))}
        </ul>
      </div>
    </aside>
  );
};

const App = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [initialLoadError, setInitialLoadError] = useState<string | null>(null);

  const [users, setUsers] = useState<User[]>([]);
  const [properties, setProperties] = useState<Property[]>([]);
  const [visits, setVisits] = useState<any[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [trainingResources, setTrainingResources] = useState<any[]>([]);
  const [calendarEvents, setCalendarEvents] = useState<any[]>([]);
  const [captaciones, setCaptaciones] = useState<any[]>([]);
  const [formats, setFormats] = useState<any[]>([]);
  const [dailyLogs, setDailyLogs] = useState<DailyLog[]>([]);
  const [appSettings, setAppSettings] = useState<{ [key: string]: string }>({});

  const [activeView, setActiveView] = useState('dashboard');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [selectedCaptacionId, setSelectedCaptacionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [modalState, setModalState] = useState<{ type: string | null; data?: any }>({ type: null, data: null });
  const [isFileUploadWarningOpen, setIsFileUploadWarningOpen] = useState(false);
  const [whatsAppModal, setWhatsAppModal] = useState({
    isOpen: false,
    recipientName: '',
    phone: '',
    message: '',
    associatedPhone: ''
  });

  const channelRef = useRef<RealtimeChannel | null>(null);

  const fetchData = useCallback(async () => {
    try {
      const dataSources = [
        { name: 'users', setter: setUsers },
        { name: 'properties', setter: setProperties },
        { name: 'visits', setter: setVisits },
        { name: 'tasks', setter: setTasks },
        { name: 'notifications', setter: setNotifications },
        { name: 'training_resources', setter: setTrainingResources },
        { name: 'calendar_events', setter: setCalendarEvents },
        { name: 'captaciones', setter: setCaptaciones },
        { name: 'formats', setter: setFormats },
        { name: 'daily_logs', setter: setDailyLogs },
      ];

      const results = await Promise.all(dataSources.map(source => supabase.from(source.name).select('*')));

      results.forEach((result, index) => {
        if (result.error) throw result.error;
        const source = dataSources[index];
        if (source.name === 'notifications') {
          source.setter(result.data.map(n => ({ ...n, timestamp: new Date(n.timestamp) })));
        } else {
          source.setter(result.data || []);
        }
      });
      setInitialLoadError(null);
    } catch (error: any) {
      setInitialLoadError(formatSupabaseError(error));
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (!session) setLoading(false);
    });

    const { data: authListener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => authListener.subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (session) {
      const loadUserAndData = async () => {
        setLoading(true);
        try {
          const profile = await getProfileForUser(session.user);
          setCurrentUser(profile);
          await fetchData();
        } catch (error) {
          setInitialLoadError(formatSupabaseError(error));
        } finally {
          setLoading(false);
        }
      };
      loadUserAndData();
    }
  }, [session, fetchData]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const handleNavigate = (view: string) => {
    setActiveView(view);
    setSelectedPropertyId(null);
    setSelectedCaptacionId(null);
    setIsSidebarOpen(false);
  };

  const handleOpenModal = (type: string, data: any = null) => setModalState({ type, data });
  const handleCloseModal = () => setModalState({ type: null, data: null });

  const renderActiveView = () => {
    if (selectedPropertyId) {
      const prop = properties.find(p => p.id === selectedPropertyId);
      if (prop) return (
        <PropertyDetails
          property={prop}
          visits={visits.filter(v => v.propertyId === prop.id)}
          tasks={tasks.filter(t => t.propertyId === prop.id)}
          users={users}
          currentUser={currentUser!}
          onBack={() => setSelectedPropertyId(null)}
          onSelectVisit={(id) => handleOpenModal('visit-details', visits.find(v => v.id === id))}
          onOpenAddVisitModalForProperty={(propId) => handleOpenModal('add-visit', { propertyId: propId })}
          onCompleteTask={async (id) => {
            await supabase.from('tasks').update({ status: TaskStatus.COMPLETED }).eq('id', id);
            fetchData();
          }}
          onOpenVisitEditor={(vId, tId) => handleOpenModal('edit-visit-from-task', { visit: visits.find(v => v.id === vId), taskId: tId })}
        />
      );
    }

    switch (activeView) {
      case 'properties':
        return <PropertyList properties={properties} currentUser={currentUser!} users={users} onSelectProperty={setSelectedPropertyId} onAddProperty={() => handleOpenModal('add-property')} onEditProperty={(p) => handleOpenModal('edit-property', p)} onDeleteProperty={(p) => handleOpenModal('delete-property', p)} />;
      case 'calendar':
        return <Calendar currentUser={currentUser!} visits={visits} calendarEvents={calendarEvents} tasks={tasks} properties={properties} users={users} onSelectVisit={(id) => handleOpenModal('visit-details', visits.find(v => v.id === id))} onOpenCalendarActionModal={(date) => handleOpenModal('calendar-action', { date })} onSelectItem={(item) => handleOpenModal('calendar-item-details', item)} />;
      case 'binnacle':
        return <BinnacleView dailyLogs={dailyLogs} users={users} currentUser={currentUser!} onDeleteLog={async (id) => { await supabase.from('daily_logs').delete().eq('id', id); fetchData(); }} onAddDailyLog={async (log) => { /* logic */ return true; }} />;
      case 'dashboard':
      default:
        return <Dashboard currentUser={currentUser!} properties={properties} visits={visits} users={users} tasks={tasks} dailyLogs={dailyLogs} onAddDailyLog={async (l) => true} onGoToTaskProperty={(id) => setSelectedPropertyId(id)} onSelectVisit={(id) => handleOpenModal('visit-details', visits.find(v => v.id === id))} onOpenAddVisitModal={() => handleOpenModal('add-visit')} onCompleteTask={(id) => {}} onOpenVisitEditor={(v, t) => {}} />;
    }
  };

  if (loading) return <div className="h-screen w-screen flex items-center justify-center">Cargando...</div>;
  if (initialLoadError) return <NetworkErrorOverlay message={initialLoadError} />;
  if (!session || !currentUser) return <Login logoUrl={appSettings.app_logo_url} />;

  return (
    <div className="min-h-screen flex bg-slate-100 text-slate-900">
      <Sidebar activeView={activeView} onNavigate={handleNavigate} currentUser={currentUser} isSidebarOpen={isSidebarOpen} />
      <div className="flex-1 flex flex-col">
        <Header currentUser={currentUser} onLogout={handleLogout} unreadCount={0} onToggleNotifications={() => setIsNotificationsOpen(true)} onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
        <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-y-auto">
          {renderActiveView()}
        </main>
      </div>

      {isNotificationsOpen && <NotificationPanel notifications={notifications} currentUser={currentUser} onClose={() => setIsNotificationsOpen(false)} onMarkAsRead={() => {}} />}

      {/* Modals rendering logic here using modalState */}
      {modalState.type === 'delete-property' && (
        <ConfirmationModal 
          title="Eliminar Propiedad" 
          message={`¿Seguro que quieres eliminar "${modalState.data.name}"?`} 
          onConfirm={async () => {
            await supabase.from('properties').delete().eq('id', modalState.data.id);
            handleCloseModal();
            fetchData();
          }} 
          onCancel={handleCloseModal} 
        />
      )}
    </div>
  );
};

export default App;

