const Dashboard = ({ currentUser, properties, visits, users, tasks, onSelectVisit, onOpenAddVisitModal, onGoToTaskProperty }: any) => {
    const isCurrentUserAdmin = currentUser.role === UserRole.ADMIN;

    const availableProperties = properties.filter((p: any) => p.status === PropertySaleStatus.AVAILABLE).length;
    const pendingTasks = tasks.filter((t: any) => t.status === TaskStatus.PENDING).length;

    return (
        <div className="space-y-8">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800">Dashboard</h1>
                    <p className="mt-1 text-lg text-slate-600">Bienvenido de nuevo, {currentUser.name}.</p>
                </div>
                {isCurrentUserAdmin && (
                    <button 
                        onClick={onOpenAddVisitModal}
                        className="inline-flex items-center justify-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-orange-500 hover:bg-orange-600"
                    >
                        <PlusIcon className="h-5 w-5" />
                        <span className="ml-2">Generar Visita</span>
                    </button>
                )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard title="Propiedades" value={availableProperties} icon={<BuildingOfficeIcon />} color="bg-green-100 text-green-600" />
                <StatCard title="Visitas" value={visits.length} icon={<CalendarDaysIcon />} color="bg-orange-100 text-orange-600" />
                <StatCard title="Tareas Pendientes" value={pendingTasks} icon={<ClipboardDocumentListIcon />} color="bg-yellow-100 text-yellow-600" />
                {isCurrentUserAdmin && <StatCard title="Trabajadores" value={users.filter((u: any) => u.role === UserRole.WORKER).length} icon={<UsersIcon />} color="bg-indigo-100 text-indigo-600" />}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white p-6 rounded-lg shadow">
                    <h2 className="text-lg font-semibold text-slate-800 mb-4">Actividad Reciente</h2>
                    <p className="text-sm text-slate-500">Aquí aparecerán tus próximas tareas y visitas.</p>
                </div>
            </div>
        </div>
    );
};

