        <div className="p-6">
          <h1 className="text-2xl font-bold text-orange-500">Aquivivir</h1>
        </div>
        <nav className="flex-1 px-4 pb-4 overflow-y-auto">
          <ul className="space-y-2">
            <NavItem icon={ChartPieIcon} label="Dashboard" isActive={activeView === 'dashboard'} onClick={() => handleNavigate('dashboard')} />
