        return <BinnacleView dailyLogs={dailyLogs} users={users} currentUser={currentUser!} onDeleteLog={() => {}} onAddDailyLog={async () => true} />;
      case 'training':
        return <TrainingCenter currentUser={currentUser!} resources={resources} users={users} onAddResource={()=>{}} onUpdateResource={()=>{}} onDeleteResource={()=>{}} onMarkAsViewed={()=>{}} />;
      case 'captaciones':
        return <CaptacionesList captaciones={captaciones} onSelectCaptacion={setSelectedCaptacionId} onAddCaptacion={() => {}} />;
      case 'users':
        return <ManageUsers users={users} currentUser={currentUser!} onAddUser={()=>{}} onUpdateUser={()=>{}} onDeleteUser={()=>{}} />;
      case 'dashboard':
      default:
        return <Dashboard currentUser={currentUser!} properties={properties} visits={visits} users={users} tasks={tasks} dailyLogs={dailyLogs} onAddDailyLog={async () => true} onGoToTaskProperty={setSelectedPropertyId} onSelectVisit={() => {}} onOpenAddVisitModal={() => {}} onCompleteTask={() => {}} onOpenVisitEditor={() => {}} />;
    }
  };

  if (loading) return <div className="h-screen w-screen flex items-center justify-center bg-slate-50 font-medium text-slate-600">Cargando Aquivivir...</div>;
  if (error) return <NetworkErrorOverlay message={error} />;
  if (!session || !currentUser) return <Login />;

  return (
    <div className="min-h-screen flex bg-slate-100">
      <aside className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 flex-shrink-0">
        <div className="p-6">
          <h1 className="text-2xl font-bold text-orange-500">Aquivivir</h1>
        </div>
        <nav className="flex-1 px-4 pb-4 overflow-y-auto">
          <ul className="space-y-2">
            <NavItem icon={ChartPieIcon} label="Dashboard" isActive={activeView === 'dashboard'} onClick={() => setActiveView('dashboard')} />
            <NavItem icon={BuildingOfficeIcon} label="Propiedades" isActive={activeView === 'properties'} onClick={() => setActiveView('properties')} />
            <NavItem icon={CalendarDaysIcon} label="Calendario" isActive={activeView === 'calendar'} onClick={() => setActiveView('calendar')} />
            <NavItem icon={ClipboardDocumentListIcon} label="Bitácora" isActive={activeView === 'binnacle'} onClick={() => setActiveView('binnacle')} />
            <NavItem icon={AcademicCapIcon} label="Capacitaciones" isActive={activeView === 'training'} onClick={() => setActiveView('training')} />
            <NavItem icon={ClipboardDocumentCheckIcon} label="Captaciones" isActive={activeView === 'captaciones'} onClick={() => setActiveView('captaciones')} />
            {currentUser.role === UserRole.ADMIN && (
              <NavItem icon={UsersIcon} label="Usuarios" isActive={activeView === 'users'} onClick={() => setActiveView('users')} />
            )}
          </ul>
        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          currentUser={currentUser} 
          onLogout={handleLogout} 
          unreadCount={notifications.filter(n => !n.readBy.includes(currentUser.id)).length}
          onToggleNotifications={() => setIsNotificationsOpen(true)}
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderContent()}
        </main>
      </div>

      {isNotificationsOpen && <NotificationPanel notifications={notifications} currentUser={currentUser} onClose={() => setIsNotificationsOpen(false)} onMarkAsRead={() => {}} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, TaskStatus, PropertySaleStatus } from '@/types';
import { BuildingOfficeIcon } from '@/components/icons/BuildingOfficeIcon';
import { ClipboardDocumentListIcon } from '@/components/icons/ClipboardDocumentListIcon';
import { CalendarDaysIcon } from '@/components/icons/CalendarDaysIcon';
import { UsersIcon } from '@/components/icons/UsersIcon';
import { PlusIcon } from '@/components/icons/PlusIcon';
import { TagIcon } from '@/components/icons/TagIcon';

const CalculatorCard = () => {
    const [amount, setAmount] = useState('');
    const [currency, setCurrency] = useState('USD');

    const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        if (/^\d*\.?\d*$/.test(value)) {
            setAmount(value);
        }
    };

    const numericAmount = parseFloat(amount) || 0;
    const alcabala = numericAmount * 0.03;
    const renta = numericAmount * 0.05;

    const formatCurrency = (value: number) => {
        return new Intl.NumberFormat(currency === 'USD' ? 'en-US' : 'es-PE', {
            style: 'currency',
            currency: currency,
        }).format(value);
    };

    return (
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Calculadora de Impuestos</h3>
            <div className="space-y-4">
                <div className="relative">
                    <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400 font-bold">
                        {currency === 'USD' ? '$' : 'S/'}
                    </span>
                    <input 
                        type="text" 
                        className="block w-full pl-10 pr-20 py-2 border border-slate-200 rounded-lg focus:ring-orange-500 focus:border-orange-500"
                        placeholder="0.00"
                        value={amount}
                        onChange={handleAmountChange}
                    />
                    <select 
                        className="absolute inset-y-0 right-0 py-0 pl-2 pr-7 border-transparent bg-transparent text-slate-500 text-sm font-bold"
                        value={currency}
                        onChange={(e) => setCurrency(e.target.value)}
                    >
                        <option value="USD">USD</option>
                        <option value="PEN">PEN</option>
                    </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-3 rounded-lg">
                        <p className="text-xs text-slate-500 font-bold">ALCABALA (3%)</p>
                        <p className="text-lg font-bold text-slate-800">{formatCurrency(alcabala)}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-lg">
                        <p className="text-xs text-slate-500 font-bold">RENTA (5%)</p>
                        <p className="text-lg font-bold text-slate-800">{formatCurrency(renta)}</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center transition-transform hover:scale-[1.02]">
        <div className={`p-3 rounded-lg ${color}`}>
            <Icon className="h-6 w-6" />
        </div>
        <div className="ml-4">
            <p className="text-sm font-medium text-slate-500">{title}</p>
            <p className="text-2xl font-bold text-slate-800">{value}</p>
        </div>
    </div>
);

const Dashboard = ({ currentUser, properties, visits, users, tasks, onOpenAddVisitModal }: any) => {
    const isCurrentUserAdmin = currentUser.role === UserRole.ADMIN;
    const availableProperties = properties.filter((p: any) => p.status === PropertySaleStatus.AVAILABLE).length;
    const pendingTasks = tasks.filter((t: any) => t.status === TaskStatus.PENDING).length;

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold text-slate-800">Dashboard</h1>
                    <p className="mt-1 text-slate-600 font-medium">Bienvenido de nuevo, {currentUser.name}.</p>
                </div>
                {isCurrentUserAdmin && (
                    <button 
                        onClick={onOpenAddVisitModal}
                        className="inline-flex items-center justify-center px-5 py-2.5 border border-transparent text-sm font-bold rounded-lg shadow-sm text-white bg-orange-500 hover:bg-orange-600 transition-colors"
                    >
                        <PlusIcon className="h-5 w-5 mr-2" />
                        Generar Visita
                    </button>
                )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard title="Propiedades" value={availableProperties} icon={BuildingOfficeIcon} color="bg-green-100 text-green-600" />
                <StatCard title="Visitas" value={visits.length} icon={CalendarDaysIcon} color="bg-orange-100 text-orange-600" />
                <StatCard title="Tareas" value={pendingTasks} icon={ClipboardDocumentListIcon} color="bg-yellow-100 text-yellow-600" />
                {isCurrentUserAdmin && <StatCard title="Equipo" value={users.length} icon={UsersIcon} color="bg-indigo-100 text-indigo-600" />}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <CalculatorCard />
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 min-h-[200px]">
                    <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center">
                        <TagIcon className="h-5 w-5 mr-2 text-orange-500" />
                        Actividad Reciente
                    </h2>
                    <div className="flex flex-col items-center justify-center h-full text-center space-y-2 opacity-50">
                        <p className="text-slate-400 font-medium italic">Pronto podrás ver un resumen aquí.</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
